codeExample:
-- SELECT com filtro e ordenação
SELECT nome, email FROM users WHERE active = true ORDER BY nome;

-- INSERT: adiciona uma linha nova
INSERT INTO users (nome, email) VALUES ('Gui', 'gui@email.com');

-- UPDATE: SEMPRE com WHERE, senão afeta a tabela inteira
UPDATE users SET email = 'novo@email.com' WHERE id = 1;

-- DELETE: mesma regra do WHERE
DELETE FROM users WHERE id = 1;

-- LEFT JOIN: todas as linhas de topic, mesmo sem progresso ainda registrado
SELECT t.category, COUNT(up.id)
FROM topic t
LEFT JOIN user_progress up ON up.topic_id = t.id AND up.session_id = 'abc-123'
GROUP BY t.category;

codeExampleBad:
-- Esqueceu o WHERE: isso atualiza TODA a tabela, não só um usuário
UPDATE users SET active = false;
-- Toda linha da tabela agora tem active = false — provavelmente não era a intenção.

-- O mesmo vale para DELETE:
DELETE FROM users;
-- Apaga TODAS as linhas da tabela. Sempre confira o WHERE antes de rodar UPDATE/DELETE em produção.
